/** @type {import('next').NextConfig} */
const path = require('path');
const fs = require('fs');
const pkg = require('./package.json');
const isExport = process.env.BUILD_MODE !== 'local';

// Load MCP shared paths from cache (generated by resolve-paths script)
let mcpPaths = null;
try {
  const pathsFile = path.resolve('./node_modules/.cache/mcp-paths.json');
  if (fs.existsSync(pathsFile)) {
    mcpPaths = JSON.parse(fs.readFileSync(pathsFile, 'utf8'));
  }
} catch (e) {
  console.warn('Could not load MCP paths:', e.message);
}

const nextConfig = {
  reactStrictMode: true,
  swcMinify: true,
  images: {
    unoptimized: true,
  },
  ...(isExport && {
    output: 'export',
    distDir: 'out',
    basePath: `/ui/${pkg.name}`,
    assetPrefix: `/ui/${pkg.name}`,
  }),
  // Transpile shared components from mercor-mcp-shared
  transpilePackages: mcpPaths ? ['mercor-mcp-shared'] : [],
  // Sync NEXT_PUBLIC_BASE_PATH with basePath for navigation.ts
  env: {
    NEXT_PUBLIC_BASE_PATH: isExport ? `/ui/${pkg.name}` : '',
  },
  webpack: (config, { defaultLoaders }) => {
    // Ensure project's node_modules is searched first for dependencies
    const projectNodeModules = path.resolve('./node_modules');
    config.resolve.modules = [projectNodeModules, ...(config.resolve.modules || ['node_modules'])];

    if (mcpPaths?.components) {
      const sharedComponents = mcpPaths.components;
      const sharedLib = mcpPaths.lib;
      const localOverrides = path.resolve('./components/overrides');

      // Add rule to compile TypeScript from shared components, lib, AND local overrides
      config.module.rules.push({
        test: /\.(tsx|ts|js|jsx)$/,
        include: [sharedComponents, sharedLib, localOverrides],
        use: defaultLoaders.babel,
      });

      // Override resolver: check local overrides first, then shared
      config.resolve.plugins = config.resolve.plugins || [];
      config.resolve.plugins.push({
        apply(resolver) {
          resolver.getHook('before-resolve').tapAsync('McpOverrideResolver', (request, resolveContext, callback) => {
            // Handle @mcp-shared/ imports (can be overridden)
            if (request.request?.startsWith('@mcp-shared/')) {
              const componentPath = request.request.replace('@mcp-shared/', '');
              const localPath = path.join(localOverrides, componentPath);

              // Check for local override (with various extensions)
              const extensions = ['', '.tsx', '.ts', '.js', '.jsx', '/index.tsx', '/index.ts', '/index.js'];
              for (const ext of extensions) {
                const fullPath = localPath + ext;
                if (fs.existsSync(fullPath)) {
                  // Found local override
                  request.request = fullPath;
                  return callback();
                }
              }

              // No local override, use shared component
              request.request = path.join(sharedComponents, componentPath);
              return callback();
            }

            // Handle @mcp-shared-base/ imports (always resolve to shared, for composition)
            if (request.request?.startsWith('@mcp-shared-base/')) {
              const componentPath = request.request.replace('@mcp-shared-base/', '');
              request.request = path.join(sharedComponents, componentPath);
              return callback();
            }

            // Handle @mcp-shared-lib/ imports (resolve to shared lib directory)
            if (request.request?.startsWith('@mcp-shared-lib/')) {
              const libPath = request.request.replace('@mcp-shared-lib/', '');
              request.request = path.join(sharedLib, libPath);
              return callback();
            }

            callback();
          });
        }
      });

      // Add aliases for IDE support (actual resolution done by plugin above)
      config.resolve.alias = config.resolve.alias || {};
      config.resolve.alias['@mcp-shared'] = sharedComponents;
      config.resolve.alias['@mcp-shared-base'] = sharedComponents;
      config.resolve.alias['@mcp-shared-lib'] = sharedLib;
    }

    return config;
  },
};

module.exports = nextConfig;
